#include <stdio.h>
#include <stdlib.h>

// Iterative method using Euclidean algorithm
int findHCFIterative(int a, int b) {
    while(b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

// Recursive method
int findHCFRecursive(int a, int b) {
    if(b == 0) return a;
    return findHCFRecursive(b, a % b);
}

// Function to find LCM using HCF
int findLCM(int a, int b, int hcf) {
    return (a * b) / hcf;
}

int main() {
    int num1, num2;

    printf("Enter two numbers: ");
    scanf("%d %d", &num1, &num2);

    // Handle negative numbers
    num1 = abs(num1);
    num2 = abs(num2);

    int hcfIterative = findHCFIterative(num1, num2);
    int hcfRecursive = findHCFRecursive(num1, num2);
    int lcm = findLCM(num1, num2, hcfIterative);

    printf("\nHCF (Iterative) of %d and %d = %d\n", num1, num2, hcfIterative);
    printf("HCF (Recursive) of %d and %d = %d\n", num1, num2, hcfRecursive);
    printf("LCM of %d and %d = %d\n", num1, num2, lcm);

    return 0;
}
