#include <stdio.h>
#include <string.h>

#define MAX_STUDENTS 100

typedef struct {
    int roll;
    char name[50];
    float marks[3];
    float average;
} Student;

Student students[MAX_STUDENTS];
int studentCount = 0;

void addStudent() {
    if(studentCount >= MAX_STUDENTS) {
        printf("Maximum students limit reached!\n");
        return;
    }

    Student s;
    printf("Enter Roll Number: ");
    scanf("%d", &s.roll);

    // Check for duplicate roll number
    for(int i = 0; i < studentCount; i++) {
        if(students[i].roll == s.roll) {
            printf("Student with roll number %d already exists!\n", s.roll);
            return;
        }
    }

    printf("Enter Name: ");
    scanf(" %[^\n]", s.name);

    printf("Enter marks in 3 subjects:\n");
    float sum = 0;
    for(int i = 0; i < 3; i++) {
        printf("Subject %d: ", i+1);
        scanf("%f", &s.marks[i]);
        sum += s.marks[i];
    }
    s.average = sum / 3;

    students[studentCount] = s;
    studentCount++;
    printf("Student added successfully!\n");
}

void displayAllStudents() {
    if(studentCount == 0) {
        printf("No students found!\n");
        return;
    }

    printf("\n%-10s %-20s %-10s %-10s %-10s %-10s\n", 
           "Roll No", "Name", "Sub1", "Sub2", "Sub3", "Average");
    printf("----------------------------------------------------------------\n");

    for(int i = 0; i < studentCount; i++) {
        printf("%-10d %-20s %-10.2f %-10.2f %-10.2f %-10.2f\n",
               students[i].roll,
               students[i].name,
               students[i].marks[0],
               students[i].marks[1],
               students[i].marks[2],
               students[i].average);
    }
}

void displayStudentAverages() {
    if(studentCount == 0) {
        printf("No students found!\n");
        return;
    }

    printf("\n%-10s %-20s %-10s\n", "Roll No", "Name", "Average");
    printf("----------------------------------------\n");

    for(int i = 0; i < studentCount; i++) {
        printf("%-10d %-20s %-10.2f\n",
               students[i].roll,
               students[i].name,
               students[i].average);
    }
}

void findTopper() {
    if(studentCount == 0) {
        printf("No students found!\n");
        return;
    }

    int topperIndex = 0;
    for(int i = 1; i < studentCount; i++) {
        if(students[i].average > students[topperIndex].average) {
            topperIndex = i;
        }
    }

    printf("\n********** TOPPER **********\n");
    printf("Roll Number: %d\n", students[topperIndex].roll);
    printf("Name: %s\n", students[topperIndex].name);
    printf("Average Marks: %.2f\n", students[topperIndex].average);
    printf("****************************\n");
}

void sortByRollNumber() {
    if(studentCount <= 1) return;

    // Bubble sort
    for(int i = 0; i < studentCount - 1; i++) {
        for(int j = 0; j < studentCount - i - 1; j++) {
            if(students[j].roll > students[j+1].roll) {
                Student temp = students[j];
                students[j] = students[j+1];
                students[j+1] = temp;
            }
        }
    }
    printf("Students sorted by roll number!\n");
}

int main() {
    int choice;

    do {
        printf("\n********** STUDENT MANAGEMENT SYSTEM **********\n");
        printf("1. Add Student\n");
        printf("2. Display All Students\n");
        printf("3. Display Student Averages\n");
        printf("4. Find Topper\n");
        printf("5. Sort by Roll Number\n");
        printf("6. Exit\n");
        printf("Enter your choice: ");
        scanf("%d", &choice);

        switch(choice) {
            case 1:
                addStudent();
                break;
            case 2:
                displayAllStudents();
                break;
            case 3:
                displayStudentAverages();
                break;
            case 4:
                findTopper();
                break;
            case 5:
                sortByRollNumber();
                break;
            case 6:
                printf("Exiting...\n");
                break;
            default:
                printf("Invalid choice! Please try again.\n");
        }
    } while(choice != 6);

    return 0;
}
```
